#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Carp qw(croak);

# ---------------------------------------------------------------------------
# Load connection parameters from environment variables.
#
# Required environment variables:
#   LEGACY_DB_NAME  – database name       (e.g. "legacy_db")
#   LEGACY_DB_HOST  – database host       (e.g. "localhost")
#   LEGACY_DB_USER  – database user
#   LEGACY_DB_PASS  – database password
#
# Optional:
#   LEGACY_DB_PORT  – database port       (default: 3306)
# ---------------------------------------------------------------------------

sub _require_env {
    my ($name) = @_;
    my $value = $ENV{$name};
    croak "ERROR: Required environment variable '$name' is not set. "
        . "Please configure it before running this application."
        unless defined $value && length $value;
    return $value;
}

sub get_db_connection {
    my $db_name = _require_env('LEGACY_DB_NAME');
    my $db_host = _require_env('LEGACY_DB_HOST');
    my $db_user = _require_env('LEGACY_DB_USER');
    my $db_pass = _require_env('LEGACY_DB_PASS');
    my $db_port = $ENV{'LEGACY_DB_PORT'} // 3306;

    my $dsn = "DBI:mysql:database=${db_name};host=${db_host};port=${db_port}";

    my $dbh = DBI->connect(
        $dsn,
        $db_user,
        $db_pass,
        {
            RaiseError        => 1,
            AutoCommit        => 1,
            PrintError        => 0,
            mysql_enable_utf8 => 1,
            mysql_auto_reconnect => 1,
        },
